  ba:	2800      	cmp	r0, #0
  bc:	d159      	bne.n	172 <nrf_getaddrinfo+0x172>
  be:	4b76      	ldr	r3, [pc, #472]	; (298 <nrf_getaddrinfo+0x298>)
